function renderBlock(block) {
  switch (block.type) {
    case 'paragraph': return <Paragraph block={block} />
    case 'heading': return <Heading block={block} />
    case 'list': return <List block={block} />
    // extension future sans casser l'existant
    default: return null
  }
}

